/* =========================================================
     FEATURED TOUR + EXPLORE BY LOCATION
     ========================================================= */

  .gy-discover-section {
    width: 100%;
    padding: 78px 5vw 86px;
    box-sizing: border-box;
    background: #f7f5ef;
  }

  .gy-discover-grid {
    display: grid;
    grid-template-columns: minmax(0, 1fr) minmax(0, 1.2fr);
    gap: 58px;

    width: 100%;
    max-width: 1480px;
    margin: 0 auto;
  }

  .gy-section-label {
    margin-bottom: 12px;

    color: #597548;
    font-family: Arial, Helvetica, sans-serif;
    font-size: 12px;
    font-weight: 800;
    letter-spacing: 0.14em;
    text-transform: uppercase;
  }

  .gy-featured-tour h2,
  .gy-location-panel h2 {
    margin: 0 0 16px;

    color: #17382c;
    font-family: Georgia, "Times New Roman", serif;
    font-size: clamp(30px, 2.4vw, 43px);
    font-weight: 600;
    line-height: 1.08;
    letter-spacing: -0.02em;
  }

  .gy-featured-tour &gt; p,
  .gy-location-intro {
    max-width: 650px;
    margin: 0 0 24px;

    color: #52615b;
    font-family: Arial, Helvetica, sans-serif;
    font-size: 16px;
    line-height: 1.65;
  }

  .gy-watch-button {
    display: inline-flex;
    align-items: center;
    justify-content: center;

    min-height: 48px;
    margin-bottom: 28px;
    padding: 12px 21px;

    color: #ffffff !important;
    background: #173f30;
    border: 1px solid #173f30;
    border-radius: 4px;

    font-family: Arial, Helvetica, sans-serif;
    font-size: 13px;
    font-weight: 800;
    letter-spacing: 0.055em;
    text-decoration: none !important;
    text-transform: uppercase;

    transition:
      transform 0.2s ease,
      background-color 0.2s ease;
  }

  .gy-watch-button:hover {
    color: #ffffff !important;
    background: #286348;
    transform: translateY(-2px);
  }

  .gy-featured-image {
    position: relative;

    display: block;
    width: 100%;
    aspect-ratio: 16 / 9;

    overflow: hidden;
    border-radius: 7px;

    background: #17382c;
    box-shadow: 0 14px 35px rgba(18, 47, 36, 0.16);
  }

  .gy-featured-image img {
    display: block;
    width: 100%;
    height: 100%;

    object-fit: cover;

    transition:
      transform 0.5s ease,
      filter 0.5s ease;
  }

  .gy-featured-image::after {
    content: "";

    position: absolute;
    inset: 0;

    background:
      linear-gradient(
        to top,
        rgba(3, 27, 20, 0.30),
        rgba(3, 27, 20, 0.03) 65%
      );
  }

  .gy-featured-image:hover img {
    transform: scale(1.035);
    filter: brightness(0.92);
  }

  .gy-featured-play {
    position: absolute;
    top: 50%;
    left: 50%;
    z-index: 2;

    display: flex;
    align-items: center;
    justify-content: center;

    width: 76px;
    height: 76px;

    color: #ffffff;
    background: rgba(7, 48, 36, 0.86);
    border: 2px solid rgba(255, 255, 255, 0.88);
    border-radius: 50%;

    font-size: 26px;

    transform: translate(-50%, -50%);
    transition:
      transform 0.25s ease,
      background-color 0.25s ease;
  }

  .gy-featured-image:hover .gy-featured-play {
    background: #2a754f;
    transform: translate(-50%, -50%) scale(1.08);
  }


  /* =========================================================
     LOCATION CARDS
     ========================================================= */

  .gy-location-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 14px;
  }

  .gy-location-card {
    position: relative;

    display: block;
    min-height: 188px;

    overflow: hidden;
    border-radius: 6px;

    background: #17382c;
    text-decoration: none !important;
    box-shadow: 0 8px 22px rgba(18, 47, 36, 0.12);
  }

  .gy-location-card:nth-child(4),
  .gy-location-card:nth-child(5) {
    grid-column: span 1;
  }

  .gy-location-card img {
    position: absolute;
    inset: 0;

    display: block;
    width: 100%;
    height: 100%;

    object-fit: cover;

    transition: transform 0.5s ease;
  }

  .gy-location-shade {
    position: absolute;
    inset: 0;

    background:
      linear-gradient(
        to top,
        rgba(3, 29, 22, 0.90) 0%,
        rgba(3, 29, 22, 0.36) 58%,
        rgba(3, 29, 22, 0.05) 100%
      );
  }

  .gy-location-name {
    position: absolute;
    left: 17px;
    right: 17px;
    bottom: 36px;
    z-index: 2;

    color: #ffffff;

    font-family: Georgia, "Times New Roman", serif;
    font-size: 22px;
    font-weight: 600;
    line-height: 1.1;
  }

  .gy-location-link {
    position: absolute;
    left: 17px;
    right: 17px;
    bottom: 15px;
    z-index: 2;

    color: #d6ed91;

    font-family: Arial, Helvetica, sans-serif;
    font-size: 11px;
    font-weight: 800;
    letter-spacing: 0.06em;
    text-transform: uppercase;
  }

  .gy-location-card:hover img {
    transform: scale(1.07);
  }

  .gy-map-note {
    margin: 20px 0 0;

    color: #6f7d76;
    font-family: Arial, Helvetica, sans-serif;
    font-size: 13px;
    font-style: italic;
    line-height: 1.5;
  }


  /* =========================================================
     DISCOVER SECTION — TABLETS
     ========================================================= */

  @media (max-width: 1050px) {
    .gy-discover-grid {
      grid-template-columns: 1fr;
      gap: 64px;
    }

    .gy-location-grid {
      grid-template-columns: repeat(3, minmax(0, 1fr));
    }
  }


  /* =========================================================
     DISCOVER SECTION — PHONES
     ========================================================= */

  @media (max-width: 700px) {
    .gy-discover-section {
      padding: 58px 22px 66px;
    }

    .gy-discover-grid {
      gap: 54px;
    }

    .gy-featured-tour h2,
    .gy-location-panel h2 {
      font-size: 32px;
    }

    .gy-location-grid {
      grid-template-columns: 1fr;
    }

    .gy-location-card {
      min-height: 210px;
    }

    .gy-featured-play {
      width: 64px;
      height: 64px;
      font-size: 22px;
    }
  }





























